const items = $input.first().json.items;
if (!items || items.length === 0) {
  throw new Error('GitHub API returned no repos. Possible rate limit hit.');
}
const repo = items[Math.floor(Math.random() * items.length)];
return [{
  json: {
    repo_name: repo.name,
    full_name: repo.full_name,
    description: repo.description || 'No description provided.',
    language: repo.language || 'Unknown',
    stars: repo.stargazers_count,
    topics: repo.topics || [],
    html_url: repo.html_url,
    readme_api_url: `https://api.github.com/repos/${repo.full_name}/readme`
  }
}];

const repoData = $('Pick Random Repo From Results').first().json;
const readmeRaw = $input.first().json.content || '';

// Decode base64 README, take first 800 chars
let readme = '';
try {
  readme = Buffer.from(readmeRaw.replace(/\n/g, ''), 'base64').toString('utf-8').substring(0, 800);
} catch(e) {
  readme = 'README not available.';
}

return [{
  json: {
    ...repoData,
    readme_excerpt: readme,
    prompt: `You are writing a 45-60 second punchy video voiceover script about a GitHub repository.\n\nWrite ONLY the spoken script - no headers, no markdown, no labels, no stage directions. Just natural flowing text that sounds great when read aloud.\n\nRepository: ${repoData.full_name}\nStars: ${repoData.stars.toLocaleString()}\nLanguage: ${repoData.language}\nDescription: ${repoData.description}\nTopics: ${repoData.topics.join(', ') || 'none listed'}\nREADME excerpt:\n${readme}\n\nKeep it under 100 words. Open with a strong hook. Explain what the project does and why developers love it. Sound excited but natural.`
  }
}];

const repoData = $('Prepare DeepSeek Script Prompt').first().json;
const script = $input.first().json.text || '';

if (!script || script.trim().length < 10) {
  throw new Error('DeepSeek returned an empty script. Aborting video build.');
}

const payload = {
  repo_name: repoData.repo_name,
  full_name: repoData.full_name,
  description: repoData.description,
  language: repoData.language,
  stars: repoData.stars,
  topics: repoData.topics,
  html_url: repoData.html_url,
  script: script.trim(),
  output_dir: 'C:\\Users\\PRECISION\\Desktop\\ANTIGRAVITY\\videos'
};

const payloadJson = JSON.stringify(payload);
const encoded = Buffer.from(payloadJson).toString('base64');

return [{ json: { ...repoData, script: script.trim(), encoded_payload: encoded } }];

const raw = $input.first().json.stdout || '';
const errOut = $input.first().json.stderr || '';

const match = raw.match(/VIDEO_PATH:(.+)/);
if (!match) {
  throw new Error(`Video builder did not return a path. stderr: ${errOut}`);
}

const videoPath = match[1].trim();
const repoData = $('Prepare Video Builder Payload').first().json;

return [{
  json: {
    video_path: videoPath,
    repo_name: repoData.repo_name,
    full_name: repoData.full_name,
    stars: repoData.stars,
    html_url: repoData.html_url,
    script: repoData.script
  }
}];
